title: $:/plugins/wikilabs/uuid7/filters/uuid7link.js
type: application/javascript
module-type: filteroperator

Filter operator that generates a single phrase link opening all input tiddlers.

Usage:
  [[TiddlerA]] [[TiddlerB]] [[TiddlerC]] +[uuid7link[]]

Output: a single phrase link string like "metal+dog,lake;hawk;pine"
  - The shared timestamp prefix is stated once
  - Each tiddler gets a minimal discriminator after ;
  - The link opens exactly the input tiddlers when used as a URL hash

\*/

"use strict";

exports.uuid7link = function(source, operator, options) {
	var phraselib = require("$:/plugins/wikilabs/uuid7/phraselib.js");

	// Collect input titles and their word arrays
	var inputTitles = [];
	var inputWords = {};
	var inputPhrases = {};
	source(function(tiddler, title) {
		var t = options.wiki.getTiddler(title);
		if(!t || !t.fields.c7) { return; }
		var enc = phraselib.encodeUUID(t.fields.c7);
		if(!enc.phrase) { return; }
		inputTitles.push(title);
		inputPhrases[title] = enc.phrase;
		var words = [];
		for(var p = 0; p < enc.phrase.length; p++) {
			var tw = enc.phrase[p].toLowerCase().split(/\s+/);
			for(var w = 0; w < tw.length; w++) {
				words.push(tw[w]);
			}
		}
		inputWords[title] = words;
	});

	if(inputTitles.length === 0) { return []; }

	// Build word arrays for ALL tiddlers with c7 (for uniqueness checks)
	var allTitles = options.wiki.filterTiddlers("[has[c7]!is[system]]");
	var allWords = {};
	var allPhrases = {};
	for(var a = 0; a < allTitles.length; a++) {
		var t = options.wiki.getTiddler(allTitles[a]);
		if(!t || !t.fields.c7) { continue; }
		var enc = phraselib.encodeUUID(t.fields.c7);
		if(!enc.phrase) { continue; }
		allPhrases[allTitles[a]] = enc.phrase;
		var words = [];
		for(var p = 0; p < enc.phrase.length; p++) {
			var tw = enc.phrase[p].toLowerCase().split(/\s+/);
			for(var w = 0; w < tw.length; w++) {
				words.push(tw[w]);
			}
		}
		allWords[allTitles[a]] = words;
	}

	// Find shared prefix + per-tiddler discriminators
	// Step 1: Find the longest common word prefix across all input tiddlers
	// Cap at timestamp triplets (words 0-8) — random triplets are for discrimination
	var firstWords = inputWords[inputTitles[0]];
	var commonLen = 0;
	// For single tiddler, cap prefix at triplet 1 (3 words) — only the most
	// stable timestamp bits. For multiple, find actual common prefix.
	var maxPrefix = inputTitles.length === 1 ? 3 : firstWords.length;
	for(var pos = 0; pos < maxPrefix; pos++) {
		var allMatch = true;
		for(var t = 1; t < inputTitles.length; t++) {
			var tw = inputWords[inputTitles[t]];
			if(pos >= tw.length || tw[pos] !== firstWords[pos]) {
				allMatch = false;
				break;
			}
		}
		if(!allMatch) { break; }
		commonLen = pos + 1;
	}

	// Step 2: Check if the common prefix alone uniquely identifies exactly our set
	// Skip for single tiddler — always want prefix + random discriminator for stability
	if(commonLen > 0 && inputTitles.length > 1) {
		var prefix = firstWords.slice(0, commonLen);
		var prefixMatches = [];
		for(var tt in allWords) {
			if(consecutiveMatch(allWords[tt], prefix)) { prefixMatches.push(tt); }
		}
		if(prefixMatches.length === inputTitles.length) {
			// Prefix alone is sufficient
			return [formatLink(prefix)];
		}
	}

	// Step 3: Discriminator search
	// Discriminators MUST come from random triplets (4-8) to survive imports.
	// With 128 words and 10k+ tiddlers, single words (~18% collision rate)
	// and pairs (~0.5%) are not reliable. Start with full triplets (16 bits
	// = 65536 combos, ~15% collision at 10k) which are the minimum reliable
	// discriminator. Fall back to two full triplets (32 bits) if needed.
	var sharedPrefixWords = commonLen > 0 ? firstWords.slice(0, commonLen) : [];
	var prefixPatterns = [];
	for(var p = 0; p < sharedPrefixWords.length; p += 3) {
		var end = Math.min(p + 3, sharedPrefixWords.length);
		prefixPatterns.push(sharedPrefixWords.slice(p, end));
	}
	var discriminators = [];
	// Random triplet indices: 3=T4, 4=T5, 5=T6, 6=T7, 7=T8
	var RANDOM_TRIPLET_START = 3;
	var RANDOM_TRIPLET_END = 6; // T7 (index 6) is last full triplet; T8 has only 2 words

	for(var i = 0; i < inputTitles.length; i++) {
		var title = inputTitles[i];
		var myPhrase = allPhrases[title];
		var discrim = null;

		// Pass 1: Position-specific full random triplet
		// Shuffle triplet order randomly so links use varied positions
		var randomTriplets = [];
		for(var rt = RANDOM_TRIPLET_START; rt <= RANDOM_TRIPLET_END; rt++) {
			randomTriplets.push(rt);
		}
		for(var s = randomTriplets.length - 1; s > 0; s--) {
			var r = Math.floor(Math.random() * (s + 1));
			var tmp = randomTriplets[s]; randomTriplets[s] = randomTriplets[r]; randomTriplets[r] = tmp;
		}
		for(var r = 0; r < randomTriplets.length && !discrim; r++) {
			var t = randomTriplets[r];
			var tw = myPhrase[t].toLowerCase().split(/\s+/);
			var candidate = prefixPatterns.concat([{words: tw, position: t}]);
			var matches = countMatchingTitlesByPatterns(candidate, allPhrases);
			if(matches.length === 1 && matches[0] === title) {
				discrim = (t + 1) + tw.join("+"); // 1-based position prefix
			}
		}

		// Pass 2: Two position-specific random triplets (last pair first)
		if(!discrim) {
			for(var t1 = RANDOM_TRIPLET_END; t1 >= RANDOM_TRIPLET_START && !discrim; t1--) {
				for(var t2 = t1 - 1; t2 >= RANDOM_TRIPLET_START && !discrim; t2--) {
					var tw1 = myPhrase[t2].toLowerCase().split(/\s+/);
					var tw2 = myPhrase[t1].toLowerCase().split(/\s+/);
					var candidate = prefixPatterns.concat([
						{words: tw1, position: t2},
						{words: tw2, position: t1}
					]);
					var matches = countMatchingTitlesByPatterns(candidate, allPhrases);
					if(matches.length === 1 && matches[0] === title) {
						discrim = (t2 + 1) + tw1.join("+") + "," + (t1 + 1) + tw2.join("+");
					}
				}
			}
		}

		// Last resort: triplets 7 + 8 position-specific
		if(!discrim) {
			var t7 = myPhrase[6].toLowerCase().split(/\s+/);
			var t8 = myPhrase[7].toLowerCase().split(/\s+/);
			discrim = "7" + t7.join("+") + ",8" + t8.join("+");
		}

		discriminators.push(discrim);
	}

	// Step 4: Build the smart link
	// First group: shared prefix + first tiddler's discriminator
	// Subsequent groups: just the discriminator (prefix inherited via ;)
	var parts = [];
	for(var i = 0; i < discriminators.length; i++) {
		if(i === 0) {
			var prefix = formatLink(sharedPrefixWords);
			parts.push(prefix ? prefix + "," + discriminators[i] : discriminators[i]);
		} else {
			parts.push(discriminators[i]);
		}
	}
	return [parts.join(";")];
};


// Check if candidate words appear as consecutive sequence in words
function consecutiveMatch(words, candidate) {
	for(var s = 0; s <= words.length - candidate.length; s++) {
		var match = true;
		for(var j = 0; j < candidate.length; j++) {
			if(words[s + j] !== candidate[j]) {
				match = false;
				break;
			}
		}
		if(match) { return true; }
	}
	return false;
}

// Count titles matching a set of AND patterns.
// Each pattern is { words: string[], position: number } where position is
// 0-based triplet index (-1 = any position).
// Legacy: plain arrays are treated as { words: arr, position: -1 }.
function countMatchingTitlesByPatterns(patterns, allPhrases) {
	var matches = [];
	for(var title in allPhrases) {
		var phrase = allPhrases[title];
		var used = [];
		var allMatch = true;
		for(var p = 0; p < patterns.length; p++) {
			var pat = patterns[p];
			var pattern = Array.isArray(pat) ? pat : (pat.words || [pat]);
			var position = (!Array.isArray(pat) && pat.position >= 0) ? pat.position : -1;
			var found = false;
			var tStart = position >= 0 ? position : 0;
			var tEnd = position >= 0 ? position + 1 : phrase.length;
			for(var t = tStart; t < tEnd; t++) {
				if(used.indexOf(t) >= 0) { continue; }
				var tripletWords = phrase[t].toLowerCase().split(/\s+/);
				for(var s = 0; s <= tripletWords.length - pattern.length; s++) {
					var match = true;
					for(var j = 0; j < pattern.length; j++) {
						if(tripletWords[s + j] !== pattern[j]) {
							match = false;
							break;
						}
					}
					if(match) {
						found = true;
						used.push(t);
						break;
					}
				}
				if(found) { break; }
			}
			if(!found) {
				allMatch = false;
				break;
			}
		}
		if(allMatch) {
			matches.push(title);
		}
	}
	return matches;
}

// Format a word array as a phrase link with triplet grouping
function formatLink(words) {
	if(words.length === 0) { return ""; }
	var parts = [];
	var i = 0;
	while(i < words.length) {
		var tripletIdx = Math.floor(i / 3);
		var tripletSize = (tripletIdx === 7) ? 2 : 3;
		var tripletStart = tripletIdx * 3;
		var chunk = [];
		while(i < words.length && i < tripletStart + tripletSize) {
			chunk.push(words[i]);
			i++;
		}
		parts.push(chunk.join("+"));
	}
	return parts.join(",");
}
","type":"application/javascript","module-type":"filteroperator"},"$:/plugins/wikilabs/uuid7/base62id.js":{"title":"$:/plugins/wikilabs/uuid7/base62id.js","text":"/*\
title: $:/plugins/wikilabs/uuid7/base62id.js
type: application/javascript
module-type: library

Base62id Encoder / Decoder
============================
Encodes and decodes 128-bit values (UUID v7) using Base62id encoding.
Based on https://github.com/sergeyprokhorenko/Base62id

The encoding adds a 2-bit prefix (binary 10) to the 128-bit value,
producing a 130-bit number that always encodes to exactly 22 characters.
The first character is always an uppercase letter (A-L).

Alphabet: 0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz
This is ASCII-sorted, so lexicographic order = numeric order.

Public API:
	encode(bytes)             → string  (22-char Base62id)
	decode(str)               → Uint8Array(16)
	fromUUID(uuidHex)         → string  (22-char Base62id)
	toUUID(b62)               → string  (UUID hex with hyphens)
	isValidB62(str)           → boolean
	extractTimestampMs(b62)   → number | null

Standalone — no TiddlyWiki dependencies.

\*/

"use strict";

// ---------------------------------------------------------------------------
// Base62id alphabet (ASCII-sorted: 0-9 A-Z a-z)
// ---------------------------------------------------------------------------

var ALPHABET = "0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz";
var BASE = 62;
var ENCODED_LENGTH = 22;

// Decoding map
var DECODE_MAP = Object.create(null);
(function() {
	for(var i = 0; i < ALPHABET.length; i++) {
		DECODE_MAP[ALPHABET[i]] = i;
	}
})();

// ---------------------------------------------------------------------------
// Big number arithmetic using arrays of 16-bit values (little-endian)
// ---------------------------------------------------------------------------

// Multiply big number by scalar, add carry
function bigMulAdd(num, mul, add) {
	var carry = add;
	for(var i = 0; i < num.length; i++) {
		var v = num[i] * mul + carry;
		num[i] = v & 0xFFFF;
		carry = (v >>> 16);
	}
	while(carry > 0) {
		num.push(carry & 0xFFFF);
		carry = carry >>> 16;
	}
}

// Divide big number by divisor, return remainder
function bigDivMod(num, divisor) {
	var remainder = 0;
	for(var i = num.length - 1; i >= 0; i--) {
		var v = (remainder << 16) | num[i];
		num[i] = (v / divisor) >>> 0;
		remainder = v % divisor;
	}
	// Trim leading zeros
	while(num.length > 1 && num[num.length - 1] === 0) {
		num.pop();
	}
	return remainder;
}

// Check if big number is zero
function bigIsZero(num) {
	return num.length === 1 && num[0] === 0;
}

// ---------------------------------------------------------------------------
// Encode: 16-byte Uint8Array → 22-char Base62id string
// ---------------------------------------------------------------------------

function encode(bytes) {
	if(!bytes || bytes.length !== 16) {
		throw new Error("encode expects a 16-byte Uint8Array");
	}

	// Build big number from bytes (big-endian) with 2-bit prefix (binary 10 = decimal 2)
	// N = (2 << 128) + D
	// Start with prefix value 2
	var num = [2];

	// Shift left by 128 bits and add each byte
	for(var i = 0; i < 16; i++) {
		bigMulAdd(num, 256, bytes[i]);
	}

	// Convert to base 62
	var chars = [];
	while(!bigIsZero(num)) {
		var rem = bigDivMod(num, BASE);
		chars.push(ALPHABET[rem]);
	}

	// Reverse (we built it LSB-first)
	chars.reverse();

	// Pad to 22 chars (should always be 22 with prefix, but safety)
	while(chars.length < ENCODED_LENGTH) {
		chars.unshift("0");
	}

	return chars.join("");
}

// ---------------------------------------------------------------------------
// Decode: 22-char Base62id string → 16-byte Uint8Array
// ---------------------------------------------------------------------------

function decode(str) {
	if(!str || str.length !== ENCODED_LENGTH) {
		throw new Error("decode expects a 22-character Base62id string");
	}

	// Convert from base 62 to big number
	var num = [0];
	for(var i = 0; i < str.length; i++) {
		var val = DECODE_MAP[str[i]];
		if(val === undefined) {
			throw new Error("invalid Base62id character: " + str[i]);
		}
		bigMulAdd(num, BASE, val);
	}

	// Extract 16 bytes (big-endian), discarding the 2-bit prefix
	// N mod 2^128 = D (the original 128-bit value)
	var bytes = new Uint8Array(16);
	for(var j = 15; j >= 0; j--) {
		var rem = bigDivMod(num, 256);
		bytes[j] = rem;
	}

	return bytes;
}

// ---------------------------------------------------------------------------
// Convert: UUID hex string ↔ Base62id
// ---------------------------------------------------------------------------

function fromUUID(uuidHex) {
	var hex = uuidHex.replace(/-/g, "");
	if(hex.length !== 32 || !/^[0-9a-fA-F]{32}$/.test(hex)) {
		throw new Error("fromUUID expects a 32-hex-char UUID string");
	}
	var bytes = new Uint8Array(16);
	for(var i = 0; i < 16; i++) {
		bytes[i] = parseInt(hex.substr(i * 2, 2), 16);
	}
	return encode(bytes);
}

function toUUID(b62) {
	var bytes = decode(b62);
	var hex = Array.from(bytes).map(function(x) {
		return ("0" + x.toString(16)).slice(-2);
	}).join("");
	return hex.slice(0, 8) + "-" + hex.slice(8, 12) + "-" + hex.slice(12, 16) + "-" +
		hex.slice(16, 20) + "-" + hex.slice(20);
}

// ---------------------------------------------------------------------------
// Validation
// ---------------------------------------------------------------------------

var B62_RE = /^[0-9A-Za-z]{22}$/;

function isValidB62(str) {
	if(!str || typeof str !== "string") { return false; }
	return B62_RE.test(str);
}

// ---------------------------------------------------------------------------
// Timestamp extraction from Base62id
// ---------------------------------------------------------------------------

function extractTimestampMs(b62) {
	if(!isValidB62(b62)) { return null; }
	// Decode to bytes, extract timestamp from first 6 bytes (same as UUID v7)
	var bytes;
	try {
		bytes = decode(b62);
	} catch(e) {
		return null;
	}
	// 48-bit timestamp from bytes 0-5 (big-endian)
	var hi = (bytes[0] * 0x100000000 + bytes[1] * 0x1000000 +
		bytes[2] * 0x10000 + bytes[3] * 0x100 + bytes[4]);
	var lo = bytes[5];
	// Reconstruct: hi already has bytes 0-4, need to combine with byte 5
	var ms = bytes[0] * 0x10000000000 +
		bytes[1] * 0x100000000 +
		bytes[2] * 0x1000000 +
		bytes[3] * 0x10000 +
		bytes[4] * 0x100 +
		bytes[5];
	return ms;
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

exports.encode = encode;
exports.decode = decode;
exports.fromUUID = fromUUID;
exports.toUUID = toUUID;
exports.isValidB62 = isValidB62;
exports.extractTimestampMs = extractTimestampMs;
