''c7:'' <code><$text text={{{ [<stripped>c32[c7]] }}}/></code>

!! Table 1: Timestamp (48-bit) — first 10 Crockford characters

<table class="wltc-debug-table">
<tr>
	<th>Base 32</th>
	<$list filter="[<stripped>split[]first[10]]" variable="ch">
		<td class="wltc-debug-char"><$text text=<<ch>>/></td>
	</$list>
</tr>
