	</$list>
</tr>
<tr>
	<th>Group</th>
	<td class="wltc-grp-ts1" colspan="6">group 1 (6)</td>
	<td class="wltc-grp-ts2" colspan="4">group 2 (4)</td>
</tr>
<tr>
	<th>Contains</th>
	<td colspan="1">2 pad + 3 ts</td>
	<td colspan="9">45 ts (total 48 ts bits)</td>
</tr>
</table>

''Timestamp:'' <$text text={{{ [<stripped>c32[ms]] }}}/> ms — <$text text={{{ [<stripped>c32[ms]format:timestamp[YYYY-0MM-0DD 0hh:0mm:0ss.XXX]] }}}/>

