''Version:'' <$text text={{{ [<stripped>c32[version]] }}}/> — ''Variant:'' <$text text={{{ [<stripped>c32[variant]] }}}/> — ''Random:'' <code><$text text={{{ [<stripped>c32[rnd]] }}}/></code>

